class UIKit {
  constructor(options) {
    if(!options) return;
    const observerOptions = {
      threshold: options.ratio || [0, 1],
      trackVisibility: options.trackVisibility || false,
      delay: options.trackVisibility ? (options.delay || 100) : 0
    };

   var io = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry && options.onLayoutChange) {
          options.onLayoutChange?.({
            ratio: entry.intersectionRatio,
            element: entry.target,
            options
          });
        }
      });
    }, observerOptions);
    if(options.container && options.items) {
      console.error(`you can't use both of items and container
      {
        container: ${options.container},
        items: ${options.items}
      }
      `);
      return;
    }
    if (options.container) {
      io.observe(options.container);
    } else if (options.items) {
      options.items.forEach((el) => {
        if (el) io.observe(el);
      });
    }
    this.options = options;
  }
  onInteraction(obj) {
  window.addEventListener("scroll",(event) => {
    const totalHeight = document.documentElement.scrollHeight; 
    const visibleHeight = window.innerHeight;
    const currentScroll = window.scrollY;
    const remaining = Math.max(0, totalHeight - (currentScroll + visibleHeight));
    const totalScrollable = totalHeight - visibleHeight;
    const percentage = (currentScroll / (totalScrollable || 1)) * 100;

    const layoutData = {
      remaining: remaining,
      actualHeight: visibleHeight,
      percentage: Math.min(100, percentage),
      isMaximum: remaining <= 1 
    };

    obj.onLayoutChange?.(layoutData);
  });
}
  onInteractionEnd(obj) {
window.addEventListener("scrollend",(event)=> {
    const totalHeight = document.documentElement.scrollHeight; 
    const visibleHeight = window.innerHeight;
    const currentScroll = window.scrollY;
    const remaining = Math.max(0, totalHeight - (currentScroll + visibleHeight));
    const totalScrollable = totalHeight - visibleHeight;
    const percentage = (currentScroll / (totalScrollable || 1)) * 100;
    const layoutData = {
      remaining: remaining,
      actualHeight: visibleHeight,
      percentage: Math.min(100, percentage),
      isMaximum: remaining <= 1 
    };
    obj.onLayoutChange(layoutData);
  });
}
  scrollTo(obj) {
    window.scrollTo({
  top: obj.top || 0,
  left: obj.left || 0,
  behavior: obj.behavior || 'smooth'
});
  }
  scrollToElement(el, behavior) {
    if(!el) return;
    const rect = el.getBoundingClientRect();
    this.scrollTo({
      top: rect.top + window.scrollY,
      left: rect.left + window.scrollX,
      behavior: behavior || 'smooth'
    });
}
  scrollToElementSmoothly(el,behavior,block) {
el.scrollIntoView({
  behavior,
  block
});
  }
  mediaQuery(condition, callback) {
var isMatched = window.matchMedia(condition);
isMatched.addEventListener("change",callback);
callback(isMatched);
  }
}